"use client";

import { useStore } from "@/lib/store/useStore";
import styles from "./CustomerLedger.module.css";
import { format } from "date-fns";
import { MessageSquare, Eye, MoreVertical } from "lucide-react";

export default function CustomerLedger() {
  const { customers } = useStore();

  return (
    <div className={styles.container}>
      <table className={styles.table}>
        <thead>
          <tr>
            <th>Customer Name</th>
            <th>Phone</th>
            <th>Total Due</th>
            <th>Last Entry</th>
            <th>Status</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {customers.length === 0 ? (
            <tr>
              <td colSpan={6} className={styles.empty}>No customers found. Try adding one via AI Assistant!</td>
            </tr>
          ) : (
            customers.map((customer) => (
              <tr key={customer.id}>
                <td>
                  <div className={styles.nameCell}>
                    <div className={styles.avatar}>{customer.name[0]}</div>
                    <span>{customer.name}</span>
                  </div>
                </td>
                <td className={styles.phone}>{customer.phone || 'N/A'}</td>
                <td className={styles.amount}>₹{customer.totalDue.toLocaleString()}</td>
                <td className={styles.date}>
                  {format(new Date(customer.lastTransactionDate), 'dd MMM, yyyy')}
                </td>
                <td>
                  <span className={`${styles.status} ${customer.totalDue > 0 ? styles.active : styles.cleared}`}>
                    {customer.totalDue > 0 ? 'Pending' : 'Cleared'}
                  </span>
                </td>
                <td>
                  <div className={styles.actions}>
                    <button className={styles.actionBtn} title="View History"><Eye size={16} /></button>
                    <button className={styles.actionBtn} title="WhatsApp"><MessageSquare size={16} /></button>
                    <button className={styles.actionBtn}><MoreVertical size={16} /></button>
                  </div>
                </td>
              </tr>
            ))
          )}
        </tbody>
      </table>
    </div>
  );
}
