"use client";

import styles from "./QuickActions.module.css";
import { UserPlus, PlusCircle, MinusCircle, History } from "lucide-react";
import { useStore } from "@/lib/store/useStore";

export default function QuickActions() {
  const { setOrbState } = useStore();

  const handleAction = (type: string) => {
    // In a real app, this might open a modal
    // For this OS feel, we can trigger an AI suggestion or quick form
    console.log(`Triggered action: ${type}`);
    setOrbState('processing');
    setTimeout(() => setOrbState('idle'), 1000);
  };

  return (
    <div className={styles.container}>
      <button className={styles.actionButton} onClick={() => handleAction('add_customer')}>
        <UserPlus size={18} />
        <span>Add Customer</span>
      </button>
      <button className={`${styles.actionButton} ${styles.credit}`} onClick={() => handleAction('add_credit')}>
        <PlusCircle size={18} />
        <span>Add Credit</span>
      </button>
      <button className={`${styles.actionButton} ${styles.payment}`} onClick={() => handleAction('add_payment')}>
        <MinusCircle size={18} />
        <span>Add Payment</span>
      </button>
      <button className={styles.actionButton} onClick={() => handleAction('history')}>
        <History size={18} />
        <span>Sync History</span>
      </button>
    </div>
  );
}
