"use client";

import { useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import styles from "./ConversationEngine.module.css";
import { useStore } from "@/lib/store/useStore";
import { format } from "date-fns";

export default function ConversationEngine() {
  const aiLogs = useStore((state) => state.aiLogs);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [aiLogs]);

  return (
    <div className={styles.container} ref={scrollRef}>
      <AnimatePresence initial={false}>
        {aiLogs.length === 0 ? (
          <div className={styles.empty}>
            <p>Ready for your first command...</p>
          </div>
        ) : (
          aiLogs.map((log, index) => (
            <motion.div 
              key={log.id || index}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className={styles.messageGroup}
            >
              <div className={styles.userMessage}>
                <span className={styles.text}>{log.command}</span>
                <span className={styles.time}>{format(log.timestamp, 'HH:mm')}</span>
              </div>
              <motion.div 
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.3 }}
                className={styles.aiMessage}
              >
                <div className={styles.aiBadge}>AI</div>
                <span className={styles.text}>{log.response}</span>
              </motion.div>
            </motion.div>
          ))
        )}
      </AnimatePresence>
    </div>
  );
}
