"use client";

import { motion } from "framer-motion";
import styles from "./AiOrb.module.css";
import { useStore } from "@/lib/store/useStore";

export default function AiOrb() {
  const orbState = useStore((state) => state.orbState);

  const getGlowColor = () => {
    switch (orbState) {
      case 'listening': return 'var(--accent-blue)';
      case 'processing': return 'var(--accent-purple)';
      case 'success': return 'var(--accent-green)';
      case 'error': return 'var(--accent-red)';
      default: return 'var(--accent-blue)';
    }
  };

  return (
    <div className={styles.container}>
      <div className={styles.orbWrapper}>
        {/* Outer Ring */}
        <motion.div 
          className={styles.ring}
          animate={{ 
            rotate: 360,
            scale: orbState === 'listening' ? [1, 1.1, 1] : 1,
            borderColor: getGlowColor()
          }}
          transition={{ 
            rotate: { duration: 10, repeat: Infinity, ease: "linear" },
            scale: { duration: 1.5, repeat: Infinity }
          }}
        />

        {/* Inner Orb */}
        <motion.div 
          className={styles.orb}
          animate={{
            backgroundColor: getGlowColor(),
            boxShadow: `0 0 40px ${getGlowColor()}`,
            scale: orbState === 'listening' ? [1, 1.2, 1] : 1
          }}
          transition={{ duration: 0.5 }}
        >
          <div className={styles.core} />
        </motion.div>

        {/* Particles / Waves */}
        {orbState === 'listening' && (
          <motion.div 
            className={styles.wave}
            initial={{ scale: 0.8, opacity: 0.5 }}
            animate={{ scale: 2, opacity: 0 }}
            transition={{ duration: 2, repeat: Infinity }}
            style={{ borderColor: getGlowColor() }}
          />
        )}
      </div>
      <p className={styles.statusText}>
        {orbState === 'idle' && "System Ready"}
        {orbState === 'listening' && "Listening..."}
        {orbState === 'processing' && "Analyzing logic..."}
        {orbState === 'success' && "Action Complete"}
        {orbState === 'error' && "Retrying..."}
      </p>
    </div>
  );
}
