import { create } from 'zustand';
import { db, type Customer, type Transaction, type AiLog } from '../db/dexie';

interface KiranaState {
  customers: Customer[];
  transactions: Transaction[];
  aiLogs: AiLog[];
  isLoading: boolean;
  
  // Orb State
  orbState: 'idle' | 'listening' | 'processing' | 'success' | 'error';
  setOrbState: (state: 'idle' | 'listening' | 'processing' | 'success' | 'error') => void;

  // Actions
  fetchData: () => Promise<void>;
  addCustomer: (customer: Omit<Customer, 'id'>) => Promise<number>;
  updateCustomer: (id: number, changes: Partial<Customer>) => Promise<void>;
  deleteCustomer: (id: number) => Promise<void>;
  clearAll: () => Promise<void>;
  addTransaction: (transaction: Omit<Transaction, 'id'>) => Promise<number>;
  addAiLog: (log: Omit<AiLog, 'id'>) => Promise<number>;
}

export const useStore = create<KiranaState>((set, get) => ({
  customers: [],
  transactions: [],
  aiLogs: [],
  isLoading: true,
  orbState: 'idle',

  setOrbState: (state) => set({ orbState: state }),

  fetchData: async () => {
    const [customers, transactions, aiLogs] = await Promise.all([
      db.customers.toArray(),
      db.transactions.orderBy('timestamp').reverse().toArray(),
      db.ai_logs.orderBy('timestamp').reverse().limit(50).toArray(),
    ]);
    set({ customers, transactions, aiLogs, isLoading: false });
  },

  addCustomer: async (customer) => {
    const id = await db.customers.add(customer as Customer);
    await get().fetchData();
    return id as number;
  },

  updateCustomer: async (id, changes) => {
    await db.customers.update(id, changes);
    await get().fetchData();
  },

  deleteCustomer: async (id) => {
    await db.customers.delete(id);
    await db.transactions.where('customerId').equals(id).delete();
    await get().fetchData();
  },

  clearAll: async () => {
    await Promise.all([
      db.customers.clear(),
      db.transactions.clear(),
      db.ai_logs.clear()
    ]);
    await get().fetchData();
  },

  addTransaction: async (transaction) => {
    const id = await db.transactions.add(transaction as Transaction);
    
    // Update customer total balance
    const customer = await db.customers.get(transaction.customerId);
    if (customer) {
      const newTotal = transaction.type === 'credit' 
        ? customer.totalDue + transaction.amount 
        : customer.totalDue - transaction.amount;
      
      await db.customers.update(transaction.customerId, { 
        totalDue: newTotal,
        lastTransactionDate: new Date()
      });
    }

    await get().fetchData();
    return id as number;
  },

  addAiLog: async (log) => {
    const id = await db.ai_logs.add(log as AiLog);
    await get().fetchData();
    return id as number;
  },
}));
