"use client";

import { useStore } from "@/lib/store/useStore";
import styles from "./OverdueList.module.css";
import { MessageSquare, ExternalLink } from "lucide-react";
import { motion } from "framer-motion";

export default function OverdueList() {
  const { customers } = useStore();

  const overdueCustomers = customers
    .filter(c => c.totalDue > 0) // For demo, any due is shown if marked overdue
    .sort((a, b) => b.totalDue - a.totalDue);

  const sendReminder = (customer: any) => {
    const message = `Hello ${customer.name}, this is a friendly reminder from your Kirana shop. Your pending balance is ₹${customer.totalDue}. Please clear it at your earliest convenience. Thank you!`;
    const encodedMessage = encodeURIComponent(message);
    window.open(`https://wa.me/${customer.phone}?text=${encodedMessage}`, '_blank');
  };

  return (
    <div className={styles.container}>
      {overdueCustomers.length === 0 ? (
        <div className={styles.empty}>No overdue accounts found.</div>
      ) : (
        overdueCustomers.map((customer, index) => (
          <motion.div 
            key={customer.id}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ delay: index * 0.05 }}
            className={styles.item}
          >
            <div className={styles.info}>
              <span className={styles.name}>{customer.name}</span>
              <span className={styles.amount}>₹{customer.totalDue}</span>
            </div>
            <div className={styles.meta}>
              <span className={styles.days}>Due 15 days ago</span>
              <button 
                className={styles.reminderButton}
                onClick={() => sendReminder(customer)}
              >
                <MessageSquare size={14} />
                Remind
              </button>
            </div>
          </motion.div>
        ))
      )}
    </div>
  );
}
