"use client";

import { useState, useRef, useEffect, useCallback } from "react";
import { Mic, Send, X, Radio } from "lucide-react";
import styles from "./InputBar.module.css";
import { useStore } from "@/lib/store/useStore";
import { parseCommand, executeCommand } from "@/lib/ai/engine";

export default function InputBar() {
  const [input, setInput] = useState("");
  const [isListening, setIsListening] = useState(false);
  const { customers, addAiLog, setOrbState } = useStore();
  
  const recognitionRef = useRef<any>(null);

  const handleSend = useCallback(async (textOverride?: string) => {
    const command = textOverride || input.trim();
    if (!command) return;

    setInput("");
    
    const parseResult = parseCommand(command, customers);
    const response = await executeCommand(parseResult);

    await addAiLog({
      command,
      response,
      intent: parseResult.intent,
      timestamp: new Date()
    });
  }, [input, customers, addAiLog, setOrbState]);

  useEffect(() => {
    if (typeof window !== "undefined") {
      const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      if (SpeechRecognition) {
        recognitionRef.current = new SpeechRecognition();
        recognitionRef.current.continuous = true;
        recognitionRef.current.interimResults = true;
        recognitionRef.current.lang = 'en-IN'; // Better for Indian accents

        recognitionRef.current.onresult = (event: any) => {
          let currentTranscript = "";
          for (let i = event.resultIndex; i < event.results.length; ++i) {
            if (event.results[i].isFinal) {
              const finalResult = event.results[i][0].transcript;
              handleSend(finalResult);
            } else {
              currentTranscript += event.results[i][0].transcript;
            }
          }
          if (currentTranscript) setInput(currentTranscript);
        };

        recognitionRef.current.onend = () => {
          if (isListening) recognitionRef.current.start();
          else setOrbState('idle');
        };

        recognitionRef.current.onerror = (event: any) => {
          console.error("Speech Recognition Error:", event.error);
          if (event.error === 'not-allowed') setIsListening(false);
        };
      }
    }
  }, [isListening, handleSend, setOrbState]);

  const toggleListening = () => {
    if (isListening) {
      setIsListening(false);
      recognitionRef.current?.stop();
      setOrbState('idle');
    } else {
      setIsListening(true);
      setOrbState('listening');
      recognitionRef.current?.start();
    }
  };

  return (
    <div className={styles.container}>
      <div className={styles.inputWrapper}>
        <button 
          className={`${styles.micButton} ${isListening ? styles.listening : ''}`}
          onClick={toggleListening}
          title={isListening ? "Always Listening Mode (ON)" : "Start Voice Assistant"}
        >
          {isListening ? <Radio size={20} className={styles.pulse} /> : <Mic size={20} />}
        </button>

        <input 
          type="text" 
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          placeholder={isListening ? "I'm listening... speak naturally" : "Type or click mic to speak..."}
          className={styles.input}
        />

        <button 
          className={styles.sendButton} 
          onClick={() => handleSend()}
          disabled={!input.trim()}
        >
          <Send size={20} />
        </button>
      </div>
      {isListening && (
        <div className={styles.listeningBar}>
          <div className={styles.barLine} />
          <span>Hands-free AI Active</span>
        </div>
      )}
    </div>
  );
}
